1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
4	
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	export function processScenario(input: any): unknown {
15	  const results: Array<{ premium: number }> = [];
16	  let quoteCount = 0;
17	  for (const step of input.steps) {
18	    const items = step.items;
19	    if (items.length === 0) {
20	      results.push({ premium: PROCESSING_FEE });
21	      quoteCount++;
22	      continue;
23	    }
24	    const countsByType: Record<string, number> = {};
25	    for (const item of items) {
26	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
27	    }
28	    let basePremium = 0;
29	    for (const [type, count] of Object.entries(countsByType)) {
30	      if ((type === "rune" || type === "moonstone") && count === 3) {
31	        basePremium += 60;
32	      } else {
33	        basePremium += count * BASE_PREMIUM_BY_TYPE[type];
34	      }
35	    }
36	    let itemSurcharges = 0;
37	    for (const item of items) {
38	      if (item.cursed) {
39	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
40	      }
41	      if (item.enchantment >= 5) {
42	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
43	      }
44	    }
45	    const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
46	    const followUpDiscount = quoteCount > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
47	    const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
48	    results.push({ premium });
49	    quoteCount++;
50	  }
51	  return { results };
52	}
